1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (underpopulation, each has 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a cell alive that has exactly 2 live neighbors", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toEqual(
17	      expect.arrayContaining([[1, 0]])
18	    );
19	  });
20	  it.todo("should keep a cell alive that has exactly 3 live neighbors");
21	  it.todo("should kill a cell with 4 live neighbors (overpopulation)");
22	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
23	  it.todo("should keep a block pattern unchanged (still life)");
24	  it.todo("should oscillate a blinker pattern (period 2)");
25	});
