1	export type Cell = [number, number];
2	
3	function countNeighbors(cell: Cell, liveCells: Cell[]): number {
4	  return liveCells.filter(
5	    (other) =>
6	      !(other[0] === cell[0] && other[1] === cell[1]) &&
7	      Math.abs(other[0] - cell[0]) <= 1 &&
8	      Math.abs(other[1] - cell[1]) <= 1
9	  ).length;
10	}
11	
12	export function nextGeneration(liveCells: Cell[]): Cell[] {
13	  return liveCells.filter((cell) => {
14	    const neighborCount = countNeighbors(cell, liveCells);
15	    return neighborCount === 2 || neighborCount === 3;
16	  });
17	}
